function(options) {
    this._handlers = {
        'progress': [],
        'cancel': [],
        'error': [],
        'complete': []
    };

    if (typeof options === 'undefined') {
        throw new Error('The options argument is required.');
    }

    if (typeof options.src === 'undefined' && options.type !== "local") {
        throw new Error('The options.src argument is required for merge replace types.');
    }

    if (typeof options.id === 'undefined') {
        throw new Error('The options.id argument is required.');
    }

    if (typeof options.type === 'undefined') {
        options.type = 'replace';
    }

    if (typeof options.headers === 'undefined') {
        options.headers = null;
    }

    if (typeof options.copyCordovaAssets === 'undefined') {
        options.copyCordovaAssets = false;
    }

    if (typeof options.copyRootApp === 'undefined') {
        options.copyRootApp = false;
    }

    if (typeof options.timeout === 'undefined') {
        options.timeout = 15.0;
    }

    if (typeof options.trustHost === 'undefined') {
        options.trustHost = false;
    }

    if (typeof options.manifest === 'undefined') {
        options.manifest = "";
    }

    if (typeof options.validateSrc === 'undefined') {
        options.validateSrc = true;
    }

    this.options = options;

    var that = this;
    var success = function(result) {
        if (result && typeof result.progress !== 'undefined') {
            that.emit('progress', result);
        } else if (result && typeof result.localPath !== 'undefined') {
            that.emit('complete', result);
        }
    };

    var fail = function(msg) {
        var e = (typeof msg === 'string') ? new Error(msg) : msg;
        that.emit('error', e);
    };

    setTimeout(function() {
        exec(success, fail, 'Sync', 'sync', [options.src, options.id, options.type, options.headers, options.copyCordovaAssets, options.copyRootApp, options.timeout, options.trustHost, options.manifest, options.validateSrc]);
    }, 10);
}

function createAppChannel (app, key) {
  assert(~['consumerChannel', 'publisherChannel'].indexOf(key),
    'Channel key must be "consumerChannel" or "publisherChannel"')
  assert(app.connection, 'Cannot create a channel without a connection')
  assert(!app[key], 'Channel "' + key + '" already exists')

  return co(function * () {
    const channel =
      app[key] =
        yield app.connection.createChannel()

    channel.__coworkersCloseHandler = module.exports.closeHandler.bind(null, app, key)
    channel.__coworkersErrorHandler = module.exports.errorHandler.bind(null, app, key)
    channel.once('close', channel.__coworkersCloseHandler)
    channel.once('error', channel.__coworkersErrorHandler)
    app.emit('channel:create', channel)

    if (key === 'consumerChannel') {
      if (app.prefetchOpts) {
        channel.prefetch(app.prefetchOpts.count, app.prefetchOpts.global)
      }
      wrap(channel, ['ack', 'nack'], function (fn, args) {
        const message = args[0]
        assert(!message.messageAcked, 'Messages cannot be acked/nacked more than once (will close channel)')

        const ret = fn.apply(this, args)
        message.messageAcked = true
        return ret
      })
    }

    return channel
  })
}

function createAppConnection (app, url, socketOptions) {
  assert(!app.connection, 'Cannot create connection if it already exists')

  return co(function * () {
    const conn =
      app.connection =
        yield amqplib.connect(url, socketOptions)

    conn.__coworkersCloseHandler = module.exports.closeHandler.bind(null, app)
    conn.__coworkersErrorHandler = module.exports.errorHandler.bind(null, app)
    conn.once('close', conn.__coworkersCloseHandler)
    conn.once('error', conn.__coworkersErrorHandler)
    app.emit('connection:create', conn)

    return conn
  })
}

