    _hashBigNumber(md, publicKey.n);
    _hashBigNumber(md, publicKey.e);
    var digest = md.digest();
    return digest.getBytes(keyczar_util.KEYHASH_LENGTH);
}

function _makeRsaKey(rsaKey) {
