    let item;

    for (let i = n - 1; i >= 0; i--) {
      item = value[i];
      v[i] = resolveReferences(
        store,
        store._isRefValue(item) ? property.get(store._data, store._parseRefKey(item)) : item,
        depth
      );
    }

    value = v;
  } else if (isPlainObject(value)) {
    const v = {};
    let item;

    for (const prop in value) {
      item = value[prop];
      v[prop] = resolveReferences(
        store,
        store._isRefValue(item) ? property.get(store._data, store._parseRefKey(item)) : item,
        depth
      );
    }

    value = v;
  }

  return value;
}

