function quickSort(a, l, h, k, c) {
  const s = [];

  let t = 0;

  s[t++] = l;
  s[t++] = h;

  while (t > 0) {
    h = s[--t];
    l = s[--t];

    if (h - l > k) {
      const p = partition(a, l, h, c);

      if (p > l) {
        s[t++] = l;
        s[t++] = p;
      }

      if (p + 1 < h) {
        s[t++] = p + 1;
        s[t++] = h;
      }
    }
  }
}

function pivot(a, l, h, c) {
  const p = (l + ((h - l) / 2)) | 0;

  if (c(a[h], a[l]) < 0) {
    [a[l], a[h]] = [a[h], a[l]];
  }

  if (c(a[p], a[l]) < 0) {
    [a[l], a[p]] = [a[p], a[l]];
  }

  if (c(a[h], a[p]) < 0) {
    [a[h], a[p]] = [a[p], a[h]];
  }

  return p;
}

function partition(a, l, h, c) {
  const p = a[pivot(a, l, h, c)];

  let i = l - 1;
  let j = h + 1;

  for (;;) {
    do {
      i++;
    } while (c(a[i], p) < 0);

    do {
      j--;
    } while (c(a[j], p) > 0);

    if (i < j) {
      [a[i], a[j]] = [a[j], a[i]];
    } else {
      return j;
    }
  }
}

function insertionSort(a, l, h, c) {
  for (let i = l + 1; i <= h; i++) {
    const x = a[i];
    let j = i - 1;

    while (j >= 0 && c(a[j], x) > 0) {
      a[j + 1] = a[j];
      j--;
    }

    a[j + 1] = x;
  }
}

